using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.UnitTests;public class ConsentServiceTests_RespondToAccessRequest_WithFakeId_ShouldReturnError : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {    "AuthService",    "ConsentService"    };    [SkippableFact]    public async Task RespondToAccessRequest_WithFakeId_ShouldReturnError()    {    await AuthenticateAsAdminAsync(ConsentClient);    var request = new { approved = true, reason = "Approved" };    var response = await PostAsJsonWithRetryAsync(ConsentClient, ApiEndpoints.AccessRequests.Respond(Guid.NewGuid()), request);        Assert.True(response.StatusCode == HttpStatusCode.NotFound || response.StatusCode == HttpStatusCode.BadRequest);    }}